sp_widget.client_script:
api.controller=function ($scope, $rootScope, spAriaFocusManager, $http, amb, $timeout, spUtil, $location, $window, nowAttachmentHandler, $log, spAriaUtil, spModal, $uibModal, spNavStateManager) {
	// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
	// Script Continued Below
	//------------------------------------------------------------------------------------------------------------------------
	var c = this;
	c.currentTab = null;
	// STRY0076291
	//c.allowSubTask = false;
	// STRY0122687
	$scope.countRelatedListsTabs = 0;

	// DFCT0011062 - count the related lists including attachments that are being shown
	$scope.countRelatedListsTabs =
		$scope.c.data.f._related_lists.filter(function(rl) {
		if (rl.showList) {
			return rl;
		}
	}).length;

	$scope.countDocumentTabs = 0;
	if(c.data._docint_widget && c.data._docint_widget._docint_tabs){
		$scope.countDocumentTabs = c.data._docint_widget._docint_tabs.length;
	}

	$scope.submitting = false;
	$scope.mandatory = [];
	$scope.errorMessages = [];
	$scope.data.show_sql = false;
	$scope.saveButtonSuffix = spUtil.getAccelerator('s');
	$scope.isPageReady = false;
	$scope.adminMenu = {
		encodedPageUrl: encodeURIComponent($location.url()),
		getClientScriptCount: function() {
			var count = 0;
			if ($scope.data.f.client_script) {
				count += $scope.data.f.client_script.onChange.length;
				count += $scope.data.f.client_script.onLoad.length;
				count += $scope.data.f.client_script.onSubmit.length;
			}
			return count;
		}
	};

	$scope.setActiveTab = function( activeTab ){
		c.currentTab = activeTab;
	};

	$scope.getActiveTab = function(){
		return c.currentTab;
	};

	$scope.isActiveTab = function( tabName, index ){
		var activeTab = $scope.getActiveTab();
$log.debug("RJ - testing - tabName: " + tabName + " - index: " + index + " - activeTab: " + activeTab + " - retrun value: " + ( activeTab === tabName || ( activeTab === null && index === 0 ) ));		
		return ( activeTab === tabName || ( activeTab === null && index === 0 ) );
	};


	// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
	// Change scroll height when Required Info is displayed
	$scope.getScrollHeight = function(mandatoryLength) {

		var scrollClassNames = 'dtech-modal-scroll-height-standard';

		if (c.data.isModal == false) {
			scrollClassNames = 'dtechNoScroll';
		} else if (c.data.omitHeader == 'true') {
			if (mandatoryLength > 0) {
				scrollClassNames = 'dtech-modal-scroll-height-omit-header-required-info';
			} else {
				scrollClassNames = 'dtech-modal-scroll-height-omit-header-standard';
			}			
		} else if (mandatoryLength > 0) {
			// isModal true, with a header
			scrollClassNames = 'dtech-modal-scroll-height-required-info';
		}

		return scrollClassNames;
	};

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs flexing; set the Tab pane position CSS class by Page ID
	$scope.getTabPanePositionCssByPageId = function() {

		var tabPanePositionClassNames = '';

		switch(c.data.page_id) {
			case 'discovertasker_processtemplatedetails':
				tabPanePositionClassNames = '';
				break;
			//case 'discovertasker_taskdetails': // Three Column
				//tabPanePositionClassNames = '';
				//break;
			//case 'discovertask_tree_bifold':
			case 'task_requests':
				if (c.data.omitHeader) {
					tabPanePositionClassNames = 'dtech-tabpane-no-header-stick-posabso';
				} else {
					tabPanePositionClassNames = 'dtech-tabpane-with-header-stick-posabso';

					if ((!!c.data.f.classification && c.data.f.classification.length > 0) &&
							(!!c.data.f.assignment_group && c.data.f.assignment_group.length > 0)) {
						tabPanePositionClassNames += ' dtech-tabpane-with-header-ribbon2-stick-top';
					} else if ((!!c.data.f.classification && c.data.f.classification.length > 0 )||
								(!!c.data.f.assignment_group && c.data.f.assignment_group.length > 0)) {
						tabPanePositionClassNames += ' dtech-tabpane-with-header-ribbon1-stick-top';
					}
				}

				break;
			default:
				tabPanePositionClassNames = '';
		}

		return tabPanePositionClassNames;
	};

	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	var watcher;
	initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				if (name.data.operation == 'delete') {
					if (c.data.parent_id) {
						c.data.sys_id = c.data.parent_id;
					} else {
						// STRY0113838
						$window.location.href = '../' + $scope.portal.url_suffix;
					}
					$scope.server.update().then(function(){
						var parms =  {table: c.data.table, sys_id: c.data.sys_id, view: c.data.view};
						// DFCT0011062 - not sure why this was being raised here
						//$rootScope.$broadcast('$taskerTabbedForm.drillDownList.click', parms);
						$location.search('table', parms.table).search('sys_id', parms.sys_id).search('spa', '1');
						// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
						afterLoadFormReturns();
					});
				}
			});
		}
	}	
	var tableId = $scope.data.sys_id != -1 ? $scope.data.sys_id : ($scope.data.f ? $scope.data.f._attachmentGUID : -1);
	spUtil.recordWatch($scope, "sys_attachment", "table_sys_id=" + tableId, function (response, data) {
		$scope.attachmentHandler.getAttachmentList();
		if (response.data) {
			var options = {};
			options.operation = response.data.operation;
			options.filename = response.data.display_value;
			options.sys_id = tableId;
			options.table = $scope.data.table;
			options.state = (response.data.record && response.data.record.state) ? response.data.record.state.value : "";
			if (options.operation === 'update' && options.state === 'not_available')
				$rootScope.$broadcast("attachment.updated", options);
		}
	});

	afterLoadFormReturns();

	// STRY0069986- RJ - Cert Push - Template DocInt Fix
	function loadDocIntWidgets() {
		// STRY0086644 - added check for DocId not provided
		// STRY0119587
		if (!c.data.hideDocuments && c.data.DocIntON && (c.data.sys_id != -1 && c.data.sys_id != '') &&
			(c.data.table == 'x_153465_discovert_route_task_instance' ||
				c.data.table == 'x_153465_discovert_discover_routing_template' ||
				c.data.table == 'x_153465_discovert_route_tasks')) {
			loadDynamicDocIntWidgets();
		}


	}

	//STRY0042748 | DI Integration: Tab Count for DocIntegrator List View provided
	//STRY0059178 | Shared Documents Folder  YOU ARE HERE!  nEED TO FIGURE OUT HOW TO ADD ANOTHER TAB.  ALSO NEED TO FIGURE OUT HOW TO GET THE DOCUMENT COUNT BELOW

	// RAJ - NOTE: - I put all of the DocInt code in one place so it is easy to find
	// We need to think about IF the counts could be in a DocInt Widget that adds multiple Tabs.
	// I am not sure that this can be done, but, if possible, we could drop the tab header as one javascript loaded file with this in it or some other way
	// IF this could be hidden in the DocInt widget, it would make it easier to add on widgets
	// the config should definitely be hidden in a DocInt widget that is added as one of the list of widgets only when admin
	// *******************************************************************************************************************************************************
	// for now, copy everything in this code block into widgets that want to use DocInt
	// *******************************************************************************************************************************************************
	//extension
	//This runs at first load.
	function loadDynamicDocIntWidgets() {
		for (var i in $scope.data._docint_widget._docint_tabs) {
			var _tab = $scope.data._docint_widget._docint_tabs[i];

			// only clear the tab if it isn't the default empty tab
			if((c.data.DocIntShareFolderON || $scope.data._docint_widget._docint_tabs[i].caption != 'Shared Documents') ){
				loadDocIntWidget($scope.data._docint_widget._docint_tabs[i]);
			}
		}
	}

	function loadDocIntWidget(tab){
		tab.widget=null;
		var widget_name = tab.widget_name;
		var widget_parameters = tab.widgetParameter;
		if(widget_name == 'docint-list-items') {
			widget_parameters = {
				vw: tab.config["docintegrator_view-refValue"],
				mapRowSysId: c.data.sys_id + "",
				readonly_flag: c.data.isActive,
				lw_name: tab.id + tab.caption,
				window_size: 20,
				config_sys_id: tab.id,
				// STRY0115311
				siblings : tab.siblings
			};
		}
		// STRY0111049 - moved outside the IF statement and also set to use widgetname 
		spUtil.get(widget_name, widget_parameters).then(function(response) {
			tab.widget = response;
		});

	}
	// STRY0120403 if filter changed, then record count will change and we will need to receive an updated count
	$scope.$on("discovertasker-widget-data-table-update_count", function (event, e) {
		if (e && e.title) {
			for (var i in $scope.data.f._related_lists) {
				var rl = $scope.data.f._related_lists[i];
				if(e.title == rl.title && rl.count != e.count){
					rl.count = e.count;
				}
			}
		}
	});

	//extension
	//This runs at first load.
	$scope.$on("docint.update_count", function (event, e) {
		// STRY0119587
		if (!c.data.hideDocuments ){
			if (e && e.source) {
				for (var i in $scope.data._docint_widget._docint_tabs) {
					//
					var _section = $scope.data._docint_widget._docint_tabs[i];
					if (e.source == _section.id + _section.caption) {
						if (e.count) {
							_section.count = e.count;
						}
						if (e.errorMessages) {
							_section.error = e.errorMessages;
						}
						break;
					}
				}
			}
		}

	});

	$scope.openDurationModal = function(){
		// call common duration modal
		var title = c.data.durationTitle + ': ' + c.data.f.title;
		x_153465_discovert.twJS.openDurationModal(spModal, title, c.data.table, c.data.sys_id);
	};
	$scope.openAssignmentModal = function(obj) {
		var title= c.data.assignmentTitle + ': ' + c.data.f.title;
		x_153465_discovert.twJS.openAssignmentModal(spModal, title, c.data.table, c.data.sys_id);
	};
	$scope.openOperationalModal = function(obj) {
		var title= c.data.operationalTitle + ': ' + c.data.f.title;
		x_153465_discovert.twJS.openOperationalModal(spModal, title, c.data.table, c.data.sys_id);
	};		
	// STRY0109208 - Add Create Icon
	$scope.openCreateModal = function() {
		var title= c.data.createTaskTitle + ': ' + c.data.f.title;
		var query = 'parent=' + c.data.sys_id;
		x_153465_discovert.twJS.openCreateModal(spModal, title, c.data.table, c.data.view, query);
	};

	// 2.8 | 2022-04-14 | mmcc | STRY0119578 - Existing Task Form- Remove DTLV icon and Task Tree View icon
	//$scope.openTreeViewModal = function(obj) {
	//	x_153465_discovert.twJS.openTreeViewModal(spModal, c.data.sys_id);
	//};

	// 2.8 | 2022-04-14 | mmcc | STRY0119578 - Existing Task Form- Remove DTLV icon and Task Tree View icon
	//// 2.7.2 | 2022-01-12 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis 
	//$scope.openDynamicTreeView = function() {
	//	var urlRef = c.data.url_Properties.portal_url_ref == undefined ? 'discovertaskerportal' : c.data.url_Properties.portal_url_ref;
	//	var redirectUrlNew = urlRef;
	//	redirectUrlNew += '?id=tasker_dynamic_task_tree&dynamic_tree=true&table=' +  c.data.table;
	//	redirectUrlNew += '&sys_id=' + c.data.sys_id; 
	//	redirectUrlNew += '&view=' + c.data.view;
//
	//	window.open(redirectUrlNew, '_blank');
	//};

	// 2.7.2 | 2022-01-12 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis 
	$scope.openOrgFullScreen = function() {
		var urlRef = c.data.url_Properties.portal_url_ref == undefined ? 'discovertaskerportal' : c.data.url_Properties.portal_url_ref;
		var redirectUrlNew = urlRef;
		redirectUrlNew += '?id=' + 'discovertasker_ouhierarchy_full_screeen';
		// redirectUrlNew += '&view=' + c.data.url_Properties.view;
		redirectUrlNew += '&table=' + c.data.table;
		redirectUrlNew += '&sys_id=' + c.data.sys_id;

		window.open(redirectUrlNew, '_blank');
	};

	// 2.7.2 | 2022-01-12 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis 
	$scope.openTaskFullScreen = function() {
		var urlRef = c.data.url_Properties.portal_url_ref == undefined ? 'discovertaskerportal' : c.data.url_Properties.portal_url_ref;
		var redirectUrlNew = urlRef;
		redirectUrlNew += '?id=' + c.data.url_Properties.pageId;
		redirectUrlNew += '&view=' + c.data.url_Properties.view;
		redirectUrlNew += '&table=' + c.data.table;
		redirectUrlNew += '&sys_id=' + c.data.sys_id;

		redirectUrlNew += '&p=';
		if (c.data.p != undefined) {
			redirectUrlNew += c.data.p;
		}

		redirectUrlNew += '&filter=';
		if (c.data.filter != undefined) {
			redirectUrlNew += c.data.filter;
		}

		window.open(redirectUrlNew, '_blank');
	};

	// RAJ - NOTE: - I put all of the DocInt code in one place so it is easy to find
	// the config should definitely be hidden in a DocInt widget that is added as one of the list of widgets only when admin
	$scope.openPlatformIntegration = function (query) {
		var widgetName = "docint-widget-modal";
		c.modalInstance = spModal.open({
			title: "",
			//message: '',
			backdrop: 'static',
			widget: widgetName,
			shared: {},            
			widgetInput: {
				embeddedWidgetId: 'widget-form',
				embeddedWidgetOptions:
				{
					table: "x_dtll2_contentint_platform_integration",
					sys_id: "-1",
					view: 'Default View',
					query: query,
					hideRelatedLists: true,
					omitHeader: true,
					hideAttachmentBtn: true,
					isModal: true,
					isPopup: false
				},
				hideRelatedLists: true,
				omitHeader: true,
				hideAttachmentBtn: true,
				isModal: true           
			},
			buttons: [],
			size: 'lg'
		}).then(function () {
			//console.log('widget dismissed');
			//alert(' c.modalInstance' +  c.modalInstance);
			//$window.location.href = "/sp";
		});
	};

	// *******************************************************************************************************************************************************
	// for now, copy everything in this code block into widgets that want to use DocInt
	// *******************************************************************************************************************************************************

	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	function loadAttachmentsWidgets() {
		if (c.data.SNAttachmentsON == true) {
			// STRY0063505 The Process Template is using "Attachments" as the "Shared Attachments" for the Process Tree
			if (c.data.table != "x_153465_discovert_discover_routing_template" || c.data.AttachmentSharedFolderON == true) {
				// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
				c.data.myAttachmentWidget = null;

				spUtil.get('tasker_task_attachments', {
					// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists; added isModal
					isModal: c.data.isModal,
					table: c.data.table,
					sys_id: c.data.sys_id,
					name: 'myAttachmentWidget'
				}).then(function(response) {
					c.data.myAttachmentWidget = response;
				});
			}
		}
		if ((c.data.AttachmentSharedFolderON == true) && (c.data.SNAttachmentsON == true)) {
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			c.data.sharedAttachmentWidget = null;
			spUtil.get('tasker_task_attachments', {
				// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists; added isMOdal
				isModal: c.data.isModal,
				table: c.data.sharedAttachTableName,
				sys_id: c.data.sharedAttachSys_ID + "",
				name: 'sharedAttachmentWidget'
			}).then(function(response) {
				c.data.sharedAttachmentWidget = response;
			});
		}

	}


	// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
	$scope.$on("sp.DiscoverListItem", function(event, params) {
		c.data.f._related_lists.forEach(function(relatedList) {
			if(relatedList.table == params.table && relatedList.filter == params.filter ) {
				relatedList.count = params.rowCount;
			}
		});
	});

	// STRY0059178 | Shared Documents Folder
	$scope.$on("tasker_task_attachments.count", function(event, e) {

		if (e) {
			if (e.source == 'sharedAttachmentWidget') {
				if (e.count) {
					$scope.data.sharedAttachmentWidgetCount = e.count;
				} else {
					$scope.data.sharedAttachmentWidgetCount = 0;
				}
			}
			if (e.source == 'myAttachmentWidget') {
				if (e.count) {
					$scope.data.myAttachmentWidgetCount = e.count;
				} else {
					$scope.data.myAttachmentWidgetCount = 0;
				}

			}
		}
	});

	// FOR THE RELATED LIST TO REFRESH THE URL
	$scope.$on('data_table.click', function(e, parms) {
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			$rootScope.$broadcast('$taskerTabbedForm.drillDownList.click', parms);
			$location.search('table', parms.table).search('sys_id', parms.sys_id).search('spa', '1');
		}

		onListClick(e, parms);
	});

	$scope.openNewModal = function(table, title, view, query, sys_id) {
			open_New_Modal(table, title, view, query, sys_id);
	};

	// STRY0097476 New Email
	$scope.openModalExportTask = function() {
// TODO - NEED TO FIND ANOTHER WAY TO OPEN THIS MODAL
//		g_form.submit('openModalExportTask');
	};

	function open_New_Modal(table, title, view, query, sys_id) {
		var formQuery = query + sys_id;
		spModal.open({
			title: title,
			backdrop:'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: table,
				sys_id: "-1",
				view: view,
				query: formQuery,
				// DFCT0010635
				omitHeader: 'true',
				// STRY0040294 - added isModal - added closing of open modal
				isModal: true //,
			},
			size: 'lg',
			buttons: [],
			// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});
	}



	//------------------------------------------------------------------------------------------------------------------------
	// END CUSTOM
	//------------------------------------------------------------------------------------------------------------------------

	c.thisPage = $location.search()['id'];


	$scope.getUIActionContextMenu = function(event) {
		var menu = [];
		if (event.ctrlKey)
			return menu;

		var contextActions = $scope.getUIActions('context');
		contextActions.forEach(function(action) {
			menu.push([action.name, function() {
				$scope.triggerUIAction(action);
			}]);
		});

		if (contextActions.length > 0)
			menu.push(null);
		menu.push([$scope.data.exportPDFMsg, function() {
			exportPDF("");
		}]);
		menu.push([$scope.data.exportPDFLandMsg, function() {
			exportPDF('true');
		}]);

		return menu;
	};

	function constructResponseHandler(response) {
		var showUpdate = true;
		// JS error occurring when response empty
		if(response){
			var notifications = response['$$uiNotification'];
			// STRY0040294 - added .length > 0.  This was erroring b/c notificatoins was not null, it was an empty array.
			// I looked in the root form.  It has this same problem.
			if (notifications && notifications.length > 0 && notifications[0].type == 'error') {
				showUpdate = false;
			}					

			return function() {
				$rootScope.$broadcast("sp.form.submitted", {
					sys_id: (response.isInsert) ? response.sys_id : $scope.data.sys_id
				});
				var message;
				var eventName = "sp.form.record.updated";
				if (response.isInsert) {
					message = $scope.data.recordAddedMsg;
					var search = $location.search();
					search.sys_id = response.sys_id;
					search.spa = 1;
					$location.search(search).replace();
				} else if (showUpdate == true) {
					message = $scope.data.updatedMsg;
				}
				$scope.data.hideRelatedLists = hideRelatedLists();
				$scope.$emit(eventName, $scope.data.f._fields);
				$rootScope.$broadcast(eventName, $scope.data.f._fields);
				$scope.status = message;
				spUtil.addTrivialMessage(message);
				$timeout(clearStatus, 2000);
			};
		}
	}

	var ctrl = this;
	// switch forms
	var unregister = $rootScope.$on('$sp.list.click', onListClick);

	$scope.$on("$destroy", function() {
		unregister();
	});

	function onListClick(evt, arg) {
		// STRY0108629
		if((arg.table == c.data.table || c.data.table == null) && 
		   c.data.sys_id != arg.sys_id){
			loadForm(arg.table, arg.sys_id);
		}
	}

	function loadForm(table, sys_id) {
		var f = {};
		$scope.data.table = f.table = table;
		$scope.data.sys_id = f.sys_id = sys_id;
		f.view = $scope.data.view;
		return $scope.server.update().then(function(){
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);

			afterLoadFormReturns();
		});
	}

	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		var p = $scope.data.page_id;
		if (p == 'discovertasker_taskdetails') {
			onListClick(e, parms);
		}
	});

	function openRelatedList(e, queryString) {
		$location.search(queryString);
		e.preventDefault();
	}

	// Show or hide related lists
	$scope.$watch('data.f._related_lists', function() {
		$scope.data.hideRelatedLists = hideRelatedLists();

	}, true);

	function hideRelatedLists() {
		if (!$scope.data.f._related_lists)
			return true;
		if ($scope.options.hideRelatedLists == true)
			return true;
		if ($scope.data.sys_id == '-1')
			return true;
		// If all related lists are visible=false then hide
		if ($scope.data.f._related_lists.length > 0) {
			for (var i in $scope.data.f._related_lists) {
				var list = $scope.data.f._related_lists[i];
				if (list.visible) {
					return false;
				}
			}
		}
		return true;
	}

	function clearStatus() {
		$scope.status = "";
	}

	function setupAttachmentHandler() {
		$scope.attachmentHandler = new nowAttachmentHandler(appendDone, appendError);

		$scope.$evalAsync(function() {
			$scope.attachmentHandler.setParams($scope.data.table, $scope.data.f._attachmentGUID, 1024 * 1024 * $scope.data.maxAttachmentSize);
		});

		$scope.$on('dialog.upload_too_large.show', function(e) {
			$log.error($scope.data.largeAttachmentMsg);
			spUtil.addErrorMessage($scope.data.largeAttachmentMsg);
		});
	}

	function afterLoadFormReturns(){
		loadAttachmentsWidgets();
		loadDocIntWidgets();
		setupAttachmentHandler();
		// Changed from page.title to data.f.title to remove post back
		if(c.data.sys_id != '-1'){
			top.document.title = c.data.f.title;
			$rootScope.$broadcast('sp.update.breadcrumbs', c.data.breadcrumbs);				
		}

	}

	function appendDone() {
		$scope.$broadcast("sp.attachments.update", $scope.data.f._attachmentGUID);
		spAriaUtil.sendLiveMessage($scope.data.attachmentSuccessMsg);
	}

	function appendError(error) {
		$scope.errorMessages.push(error);
		spUtil.addErrorMessage(error.msg + error.fileName);
	}

	if ($scope.data.f.title) {
		$scope.$emit('sp.widget-modal.set-aria-label', $scope.data.f.title);
	}
};

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.10.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// CUSTOM    Some CSS selectors will be found in Tasker Overall Style Sheet
//------------------------------------------------------------------------------------------------------------------------

/* 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
Have modal fit the viewport height with its own scrollbar start
*/
.dtech-modal-scroll-height-omit-header-required-info {
  max-height: calc(100vh - 352px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-omit-header-standard {
  max-height: calc(100vh - 272px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-required-info {
  max-height: calc(100vh - 525px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-standard {
  max-height: calc(100vh - 471px);
  overflow-y: auto;
  padding-right: 15px;
}
/* Have modal fit the viewport height with its own scrollbar end */

// DFCT0010657
#loading-spinner {
  animation: loading 2s infinite linear;
}

@keyframes loading {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(359deg);
  }
}

/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
  border-left-style: solid;
  border-left-color: $primary;
  border-left-width: 5px;
  color: $primary;
  padding-top: 8px;
  padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
  //font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


/*
Set Classification color for banner (aka rectangle)
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
See Tasker Theme and CSS include: Classification Banner CSS Include
.taskform-classification-banner 
*/

/*
Set Restricted Group color for banner (aka rectangle)
2.7.0 | 2021-08-09 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance
See Tasker Theme and CSS include: Restricted Group Banner Style Sheet
.dtech-restricted-group-banner
*/



//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------

/* 2.7.1 | 2021-12-15 | mmcc | DFCT0010716 - On Tabs (OU, Task) the icons did not align correctly with text at the top of the page */
.btn-form-menu {
  /* vertical-align: inherit;
  padding: inherit; */
  background: none;
  padding: 10px 0;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

/*
2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
.dtech-field-error-label {} replaces below; Find it in Tasker Theme > Tasker Form Error Overrides Style Sheet
This widget is not using the below CSS selector
.sc-field-error-label {
margin-right: .5em;
display: inline-block;
background-color: $sc-field-error-color;
}
*/

.comment {
  font-weight: bold;
  margin-top: 2px;
  margin-bottom: 2px;
}
.mce-panel, .mce-btn {
  background-image: none;
  background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

/* 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
Have modal fit the viewport height with its own scrollbar start
*/
.timeline-container {
  /* max-height: 50vh; */
  max-height: calc(100vh - 611px);
  height: 100%;
  overflow-y: auto;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
    outline: thin dotted;
    outline: 5px auto $input-border-focus;
    outline-offset: -2px; 
  }
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
  background-color: $state-success-text;
}

.text-info-alt {
  background-color: $state-info-text;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: FORM
//------------------------------------------------------------------------------------------------------------------------
//
// 2.8 | 2022-03-29 | raj  |  STRY0119587 - Task Form Page Layout- Layout: Requests - Initial Tasker Tabs widget
// 2.8 | 2022-04-14 | mmcc | STRY0119578 - Existing Task Form- Remove DTLV icon and Task Tree View icon
//                                      In HTML in Task Full Screen icon section, based on omit_icons and sys_id then show the Divider; 
//                                        In Header Icons section, Remove html for DynamicTreeView16, TreeNodes16 and Divider;
//                                      In Server script, comment out code for setting objects data.TreeNodes16 and data.DynamicTreeView16
//                                      In Client controller, Comment out code for openDynamicTreeView() and openTreeViewModal()
//                                      Changes made in HTML, Server script and Client controller
// 2.8 | 2022-05-20 | raj  |  STRY0122592 - Place holder:  clean up the mobile document view to remove information tab and the action buttons.
//                                      changes in server script, and html (allow task filter to be removed from the screen)
// 2.8 | 2022-05-23 | raj  |  DFCT0010937 - New Template DOES NOT correctly redirect to the Templates.  It is redirecting to the New Task form. 
//                                      changes in HTML Only
// 2.8 | 2022-07-16 | raj  |  STRY0122687 - (Stretch) Task Form- Remove tabs if only one exists on that page
//                                      changes in Server Script and HTML
// 2.8 | 2022-07-16 | raj  |  STRY0120159 - Task Form- New Icons to Filter "This Task or All Descendants"
//                                      changes in Server Script and HTML
// 2.8 | 2022-07-19 | mmcc | STRY0118268 - Stretch- Post Fixed Header+Action Bar for Modals- Clean up to display more content on screen 
//                                      In HTML, under <div> for ngif=!data.omitHeader removed block of code for Banners section;
//                                        Between panel heading and panel body add the new Banners sections code;
//                                        In the panel footer, removed code forClassification; added new code for Classification above it
//                                        so the ribbon touch the edge like do by the panel heading.
//                                      Changes made in HTML, Style sheets for Classification and Restricted Group, Pages touched
// 2.8 | 2022-07-24 | raj  |  DFCT0011062 - When viewing a task in the "Document Management" task form view the task does NOT display the tabs "My Attachments" and "Shared Attachments"
//                                      Changes in Server Script, Client Controller and HTML
// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer
//                                      In HTML, removed ng-scope's as AngularJS should add; added flexbox
//                                      In CSS, moved to Overall stylesheet: DFCT0010728 flexbox ellipsis start; 
//                                      removed .dtech-align-text-icons, .dtech-align-icons-paperclip and .panel .panel
//                                      In Server script, add bifold and in in var rlParams;
//                                      In Client controller, fixed spacing, added getTabPanePositionCssByPageId()
//                                      Changes made in HTML, CSS, Server script and Client controller.
// 2.8 | 2022-08-02 | mmcc | Patch DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer
//                                      In HTML, update Ribbons section var's was using data.f .classification and .assignment_group
//                                      and now using data. classification and .assignment_group;
//                                      Bottom Ribbon section has update from data.f to data.classification.
//                                      In Server script, add if to set data. classification and assignment_group; format 1. CUSTOM: CLASSIFICATION BAR
//                                      Changes made in HTML and Server script.
//
//------------------------------------------------------------------------------------------------------------------------

// form functionality - URL parameter driven
(function($sp, input, data, options, gs) {
	// DFCT0010657
	var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
	var url_Properties = {};

	data.loadingIndicator = false;

	/* "use strict"; -linter issues */
	// populate the 'data' variable
	data.attachmentUploadSuccessMsg = gs.getMessage("Attachment upload was successful");
	data.recordAddedMsg = gs.getMessage("Record Added");
	data.updatedMsg = gs.getMessage("updated_uppercase");
	data.exportPDFLandMsg = gs.getMessage("Export to PDF (landscape)");
	data.addAttachmentMsg = gs.getMessage("Add an attachment");
	data.maxAttachmentSize = parseInt(gs.getProperty("com.glide.attachment.max_size", 1024));
	if (isNaN(data.maxAttachmentSize))
		data.maxAttachmentSize = 24;
	data.largeAttachmentMsg = gs.getMessage("Attached files must be smaller than {0} - please try again", "" + data.maxAttachmentSize + "MB");
	data.attachmentSuccessMsg = gs.getMessage("Attachment successfully uploaded");

	data.hasRoleTaskerUser = gs.hasRole('x_153465_discovert.tasker_user');

	data.emptyStateTemplate = options.empty_state_template;
	// STRY0108629
	data.omit_icons=(input || {}).omit_icons || (options || {}).omit_icons || false; 

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; add final false
	data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader || false;

	// STRY0120159 
	data.hideTaskFilter = (input || {}).hideTaskFilter || (options || {}).hideTaskFilter;
	data.showStatesMultipleBar = (input || {}).showStatesMultipleBar || (options || {}).showStatesMultipleBar;
	//------------------------------------------------------------------------------------------------------------------------
	// CUSTOM
	//------------------------------------------------------------------------------------------------------------------------
	// START - RAJ Remove post back on Modals
	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added; add || false
	// data.isModal = (input || {}).isModal || (options || {}).isModal;
	data.isModal = (input || {}).isModal || (options || {}).isModal || false;

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; set bifold
	data.bifold = (input || {}).bifold || (options || {}).bifold || false;
	data.isBottomRibbonShown = (input || {}).isBottomRibbonShown || (options || {}).isBottomRibbonShown || false;

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; add omitHeader
	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis
	// STRY0115843 - added bifold to this
	convertToBool(['bifold', 'isBottomRibbonShown', 'omitHeader', 'omit_icons', 'isModal']);


	data.page_id = $sp.getParameter("id");
	data.sys_id = $sp.getParameter("sys_id");
	data.filter = $sp.getParameter("filter") || $sp.getValue('filter');
	data.isValid = true;
	data.current_user = gs.getUserID();
	//------------------------------------------------------------------------------------------------------------------------

	if (input) {
		var myUserObject = gs.getUser();
		var currentUser = myUserObject.getDisplayName();

		data.table = input.table;
		data.sys_id = input.sys_id;
		data.view = input.view;

		//STRY0056591
		if (input.parent)
			data.parent = input.parent;
		// STRY0108170 - NOTE: this should pull all values off o a filter 
		// 								to avoid adding all fields being passed like parent above
		if (input.u_ou_parent)
			data.u_ou_parent = input.u_ou_parent;

		//KT REQUEST TYPE
		data.u_request_type = input.u_request_type;

		var result = {};
		if (input._fields) {
			result = $sp.saveRecord(input.table, input.sys_id, input._fields);
			data.sys_id = result.sys_id;
		}

		if (input.sys_id == '-1')
			data.isNewRecord = true;		
	} else {
		data.table = options.table || $sp.getParameter("t") || $sp.getParameter("table") || $sp.getParameter("sl_table");
		data.sys_id = options.sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");
	}

	if (input) {
		data.query = $sp.getParameter("query") || options.query || input.query;
	} else {
		data.query = $sp.getParameter("query") || options.query || "";
	}
	data.f = {};
	if (!data.table) {
		return;
	}

	// STRY0114645 - if task table and not a new item, look up the form to use.  If new task, the view will be passed
	if(data.table == 'x_153465_discovert_route_task_instance'){
		// set view to blank to load system default by default or the view based on view rule for the task
		var view = '';
		if(data.sys_id == -1){
			// for new items data.view will be set on the input for a modal, and on the url for a full page new item
			view = data.view || $sp.getParameter("view");
		}
		url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id, view);
		data.view = url_Properties.view;
	} else {
		data.view = data.view || $sp.getParameter("view") || "sp"; // SP default
	}

	// TODO Multi-language
	data.OrgFullscreen16 = {"src":'Fullscreen16.svg', "title": gs.getMessage("Open Organizational Hierarchy in full screen view"), "alt": gs.getMessage('Full Screen View')};
	data.TaskFullscreen16 = {"src":'Fullscreen16.svg', "title": gs.getMessage("Open task in new tab"), "alt": gs.getMessage('Open Task')};	

	// STRY0120403
	var msgKeyTaskFilter24 = "Tasker - " + data.page_id + " - TaskFilter24.svg";
	var msgTaskFilter24 = gs.getMessage(msgKeyTaskFilter24);
	// if the key and message are the same, then no message for this page, load the default message
	if(msgTaskFilter24 == msgKeyTaskFilter24){
		msgTaskFilter24 = gs.getMessage("Tasker - Show results for this Task only");		
	}
	data.TaskFilter24 = {"src":'TaskFilter24.svg', "title": msgTaskFilter24, "alt": msgTaskFilter24};

	// STRY0120403
	var msgKeyTaskFilterList24 = "Tasker - " + data.page_id + " - TaskFilterList24.svg";
	var msgTaskFilterList24 = gs.getMessage(msgKeyTaskFilterList24);
	// if the key and message are the same, then no message for this page, load the default message
	if(msgTaskFilterList24 == msgKeyTaskFilterList24){
		msgTaskFilterList24 = gs.getMessage("Tasker - Show results for this Task and all descendants");

	}
	data.TaskFilterList24 = {"src":'TaskFilterList24.svg', "title": msgTaskFilterList24, "alt": msgTaskFilterList24};

	if(data.omit_icons!=true){
		// 2.8 | 2022-04-14 | mmcc | STRY0119578 - Existing Task Form- Remove DTLV icon and Task Tree View icon
		// data.TreeNodes16 = {"src":'TreeNodes16.svg', "title": gs.getMessage("Open Task Tree View"), "alt": gs.getMessage('Task Tree View')};
		// 2.8 | 2022-04-14 | mmcc | STRY0119578 - Existing Task Form- Remove DTLV icon and Task Tree View icon
		// STRY0114212
		// data.DynamicTreeView16 = {"src":'DynamicTreeView16.svg', "title": gs.getMessage("Go to Dynamic Tree View page"), "alt": gs.getMessage('Dynamic Tree View')};
		data.Schedule16 = {"src":'Schedule16.svg', "title": gs.getMessage("Open Duration"), "alt": gs.getMessage('Duration')};
		// DFCT0010649
		data.Member16 = {"src":'Member16.svg', "title": gs.getMessage("Open Assignment"), "alt": gs.getMessage('Assignment')};
		// STRY0112002
		data.Information16 = {"src":'Information16_Black.svg', "title": gs.getMessage("Open Information"), "alt": gs.getMessage('Information')};
		data.Divider = {"src":'Divider_Black.svg', "title": "", "alt": ""};
		// DFCT0010654
		var genericAddTitle = '';
		var genericAddAlt = '';
		switch (data.table){
			case "x_153465_discovert_route_task_instance": case 'x_153465_discovert_route_tasks':
				genericAddTitle = gs.getMessage('Add a SubTask');
				genericAddAlt = gs.getMessage('Create a SubTask');
				break;
			case "x_153465_discovert_discover_office_hierarchy": 
				genericAddTitle = gs.getMessage('Add a Sub OU');
				genericAddAlt = gs.getMessage('Create a Sub OU');
				break;
		}

		data.GenericAdd16 = {"src":'GenericAdd16.svg', "title": genericAddTitle, "alt": genericAddAlt};

		// STRY0111888 - DFCT0010602 - DFCT0010603
		data.LockOpenBadge12 = {"src":'LockOpenBadge12.svg', "title": "Permissive Organizational Unit", "alt": "Organizational Unit is Permissive"};
		data.RestrictedBadge12 = {"src":'RestrictedBadge12.svg', "title": "OU does not allows Useers to be Tasked by other users", "alt": "OU Prevents Permissive Tasking"};			
		// STRY0091260
		data.durationTitle = gs.getMessage('Tasker - Title - Duration Modal');
		data.assignmentTitle = gs.getMessage('Tasker - Title - Assignment Modal');
		data.operationalTitle = gs.getMessage('Tasker - Title - Operational Modal');
		// STRY0109208 - Add Create Icon
		data.createTaskTitle = gs.getMessage('Create Subtask');
	}

	// STRY0113838
	data.url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id,data.view);

	// 2.7.0 | 2021-09-07 | mmcc | STRY0105158 - After creation of a new template, redirect is showing the wrong widget on the right column
	// From new template page, get the Top task for the Template Details Page
	if (data.page_id == 'discovertasker_processtemplatedetails' &&
		data.table == 'x_153465_discovert_discover_routing_template') {
		var grTemp = new GlideRecord('x_153465_discovert_discover_routing_template');
		if (grTemp.get(data.sys_id)) {
			data.sys_id = grTemp.getValue('parent_task_def');
			data.table = 'x_153465_discovert_route_tasks';
		}
	}

	if (gs.tableExists(data.table) == false) //if (!GlideTableDescriptor.isValid(data.table)) //for GLOBAL app
		return;

	if (!data.sys_id)
		return;

	//Possible Disabled for Restricted Tasks
	var rec = new GlideRecord(data.table);

	if (rec.get(data.sys_id)) {
		data.isValid = rec.isValid() || data.sys_id == "-1";
	} else {
		data.isValid = data.sys_id == "-1";
	}

	if (!data.isValid)
		return;

	// 2.8 | 2022-08-02 | mmcc | DFCT0011122 - Page Task Requests needs flexing; get Classification and Restricted Group for Ribbon
	if (data.table == 'x_153465_discovert_route_task_instance') {
		data.classification = rec.getDisplayValue("classification");
		data.restrictedGroup = rec.getDisplayValue("assignment_group");
	}

	if (rec.parent) {
		data.parent_id = rec.getValue('parent');
	} else {
		data.parent_id = undefined;
	}

	// STRY0097476
	data.emailEnabled = (data.table == "x_153465_discovert_route_task_instance" && new uiConditionCheck().displaySendTaskAsEmailUIAction(rec));

	// STRY0063746 - this function takes different glide record types and returns the documents, attachments and shared values for that object
	var tDS = new taskerDocumentScripts();
	var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(rec);

	//------------------------------------------------------------------------------------------------------------------------
	// CUSTOM: DOC. INT INTEGRATION - INITIALIZING VARIABLES 
	//------------------------------------------------------------------------------------------------------------------------
	//STRY0063746 - this function takes different glide record types and returns the documents, attachments and shared values for that object
	data.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn;
	data.DocIntON = currentAttachDocSettings.docIntDocumentsOn;
	//STRY0059178 | Shared Documents Folder
	data.DocIntShareFolderON = currentAttachDocSettings.sharingDocuments;
	data.AttachmentSharedFolderON = currentAttachDocSettings.sharingAttachments;

	data.table = rec.getRecordClassName();
	var table = new GlideTableHierarchy(data.table);
	data.tableHierarchy = table.getTables();
	data.canWrite = rec.canWrite();
	// STRY0050440
	data.canCreate = rec.canCreate();
	var hasRecordAccess = data.sys_id == "-1" ? rec.canCreate() : data.canWrite;

	//STRY0014160: If user doesn't have Read access, stop here.
	data.hasRecordReadAccess = true;
	if (data.table == "x_153465_discovert_route_task_instance") {
		data.hasRecordReadAccess = rec.canRead();
		if (!data.hasRecordReadAccess) {
			// STRY0105791
			var link = '<a href="../' + data.service_portal_url_suffix + '">Tasker Portal</a>';
			var message = 'You do not have permission to view this Task. ' + link + ' .<br/>';
			gs.addErrorMessage(message);
			return;
		}
	}

	// STRY0111888
	data.permissiveOUTasking = false;
	if (data.table == "x_153465_discovert_discover_office_hierarchy") {
		data.permissiveOUTasking = gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off'; 
		data.taskingUnlocked = rec.u_ou_is_permissive == true;
	}

	data.f = $sp.getForm(data.table, data.sys_id, data.query, data.view);

	// STRY0063505 | in debugging the process docs story, we realized data.isActive was only set if the field was on the form.
	data.isActive = false;
	if (data.f._fields.active) {
		data.isActive = data.f._fields.active.value;
	} else {
		// STRY0063505 |	NOTE: if the active field exists, use it.  If not, look for u_active, if neither, accept the default setting of false
		if (rec.isValidField('active')) {
			data.isActive = rec.active;
		} else if (rec.isValidField('u_active')) {
			data.isActive = rec.u_active;
		} // otherwise will default to false setting above.
	}

	data.canAttach = data.canWrite && gs.hasRole(gs.getProperty('glide.attachment.role')); //&& (data.isActive == 'true')


	//------------------------------------------------------------------------------------------------------------------------
	// BEGING CUSTON
	//------------------------------------------------------------------------------------------------------------------------

	//------------------------------------------------------------------------------------------------------------------------
	// 1. CUSTOM: CLASSIFICATION BAR
	//------------------------------------------------------------------------------------------------------------------------
	// STRY0063505 | Include Attachments since we dropped attachment properties
	// The fitler needs the "sys_id" of the object for attachments and Shared Attachments
	// get those sys_ids based on the table, then use it to set the filter
	// Needed this additional If statement b/c Task instances users task tree object
	// Process Template is just that rec sys_id
	// Process Task Template is the Process Template sys_id as the filter
	var myAttachSys_ID = data.sys_id; // set to the defualt
	data.sharedAttachSys_ID = data.sys_id + ''; // set to the defualt
	data.sharedAttachTableName = '';

	if (data.table == "x_153465_discovert_route_task_instance") {
		data.sharedAttachSys_ID = rec.u_task_tree.sys_id + '';
		data.sharedAttachTableName = 'x_153465_discovert_task_tree';
	}
	if (data.table == "x_153465_discovert_discover_routing_template") {
		data.sharedAttachSys_ID = data.sys_id + '';
		data.sharedAttachTableName = 'x_153465_discovert_discover_routing_template';
	}
	if (data.table == "x_153465_discovert_route_tasks") {
		// STRY0063505 | This table points at the Process Template Table instead of the Process Template Task table for the shared attachments
		data.sharedAttachSys_ID = rec.tasker_process_definition.sys_id + '';
		data.sharedAttachTableName = 'x_153465_discovert_discover_routing_template';
	}

	if (data.table == "x_153465_discovert_war_sar_reporting" && data.sys_id != -1) {
		if (data.f._fields.classification) {
			data.f.classification = data.f._fields.classification.displayValue;
		}
	}

	//In preparation to go-live with Delivery Customization: 04.18.20
	if (data.table == "x_153465_discovert_route_task_instance" && data.sys_id != -1) {
		if (data.f._fields.number) {
			data.number = data.f._fields.number.displayValue;
		}

		// STRY0051139
		data.task_name = rec.task_name; //data.number + ": " + data.f._fields['short_description']["displayValue"];
		data.f.task_instance__state = '';
		if (data.f._fields.classification) {
			data.f.classification = data.f._fields.classification.displayValue;
		}

		if (data.f._fields.assignment_group) {
			data.f.assignment_group = data.f._fields.assignment_group.displayValue;
		}

		// 2.7.0 | 2021-11-1 | mmcc | DFCT0010601 - Deleting the Top Task logs an error: The Task Tree was not created for Task
		if (!rec.u_task_tree && rec.number.length > 0) {
			gs.error('The Task Tree was not created for Task: ' + rec.number + '.  Please contact your Tasker administrator to check on the fix script.');
		}
	}

	if (data.table == "x_153465_discovert_discover_routing_template" & data.sys_id != -1) {
		if (data.f._fields.template_name) {
			data.f.template_name = data.f._fields.template_name.displayValue;
		}
	}

	//------------------------------------------------------------------------------------------------------------------------
	// 2. CUSTOM: TABS
	//------------------------------------------------------------------------------------------------------------------------
	// DFCT0010482 
	if(data.table == 'x_153465_discovert_route_task_instance'){
		data.canCreateSubTask = new uiConditionCheck().canCreateSubTask(rec);	
	} else {
		data.canCreateSubTask = undefined;
	}
	// STRY0119587 - load lists to show from options
	var arrRelatedLists= options.relatedLists_to_include;
	data.hideActivity = options.hideActivity;
	data.hideDocuments = options.hideDocuments;
	data.hideRelatedLists = options.hideRelatedLists;

	// STRY0122687 - count tabs
	data.tabCount = 0;

	// STRY0120403
	data.task_id = -1;
	if(data.table=='x_153465_discovert_route_task_instance' && data.sys_id!=-1){
		data.task_id = data.sys_id;
	}
	// DFCT0011062 need to process related lists to show documents if documents are not hidden
	if(!data.hideRelatedLists || !data.hideDocuments){
		var rlParams =	{
			// STRY0120159 
			task_id: data.task_id,
			hideTaskFilter: data.hideTaskFilter,
			showStatesMultipleBar: data.showStatesMultipleBar,
			arrRelatedLists: arrRelatedLists, 
			f_related_lists: data.f._related_lists,
			rec: rec, 
			table: data.table,
			canCreateSubTask: data.canCreateSubTask, 
			emailEnabled: data.emailEnabled,
			hideDocuments: data.hideDocuments,
			// DFCT0011062 improves efficiency of what is loaded to HTML
			hideRelatedLists: data.hideRelatedLists,
			page_id: data.page_id,
			view: data.view, 
			isModal: data.isModal,
			// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs flexing; set bifold
			bifold: data.bifold,
			sharedAttachSys_ID: data.sharedAttachSys_ID,
			attachmentSharedFolderON: data.AttachmentSharedFolderON, 
			myAttachSys_ID: myAttachSys_ID,
			attachmentsON: data.SNAttachmentsON
		};	
		data.f._related_lists = new TaskWidgetData().loadRelatedLists(rlParams);
		// STRY0122687 - count tabs
		data.tabCount += data.f._related_lists.length;
	}
	// STRY0061245 - while looking at adding attachments, this code was repeated in the for loop each time
	if (options.page) {
		var page = new GlideRecord('sp_page');
		if (page.get(options.page))
			data.page = page.getDisplayValue('id');
	}
	if (!data.page) {
		data.page = "form";
	}

	//------------------------------------------------------------------------------------------------------------------------
	// CUSTOM: ATTACHMENTS AND SHARED ATTACHMENTS
	//------------------------------------------------------------------------------------------------------------------------
	// STRY0059424 | Include Attachments since we dropped attachment properties
	// STRY0061245 | Include Attachments since we dropped attachment properties
	// STRY0063505 | The data.task_sysid field was used only below.  
	data.sharedAttachmentWidgetCount = 0;
	data.myAttachmentWidgetCount = 0;
	// DFCT0010343 - TUP - moved creation of attachments to client script

	//------------------------------------------------------------------------------------------------------------------------
	// 3. CUSTOM: N TAB: AUDIT WIDGET 
	//------------------------------------------------------------------------------------------------------------------------
	// 

	// STRY0119587 - only load if activity requested
	if(!data.hideActivity){
		// STRY0122687 - count tabs
		data.tabCount += 2;

    //------------------------------------------------------------------------------------------------------------------------
    // Box 4: Activity Log
    //------------------------------------------------------------------------------------------------------------------------
    data.table_audit = 'x_153465_discovert_activity_view';
    var filter_audit = '';
    //filter_audit = 'taskid_u_all_ancestors_tasksLIKE'+ data.sys_id+'^journalid_valueNOT LIKERequest has been';
		filter_audit = 'taskid_sys_id=' + data.sys_id;
    var o_audit = "journalid_sys_created_on";
    var d_audit = "desc";
    var subTasksActivity_Options = {
				task_id: data.task_id,
				hideTaskFilter: data.hideTaskFilter,
        title: 'Activity Log',
        table: data.table_audit,
        filter: filter_audit,
				isModal: data.isModal,

        enable_filter: true,
        show_keywords: true,
        show_breadcrumbs: true,

        view: 'dtlv_activity_log',
				platform_view: 'pfm_dtlv_activity_log',			

        //display_field: 'number',
        glyph: 'comment-o',
        open_row_details_in_modal: true,
        o: o_audit,
        d: d_audit
    };
		data.activityLogs = [];
		var subTasksActivity = {};
		subTasksActivity.widget = $sp.getWidget('discovertasker-widget-data-table', subTasksActivity_Options); //widget-data-table //discovertasker-widget-data-table
		data.activityLogs.push(subTasksActivity);

		data.widgetInstanceAuditNotes = $sp.getWidget('widget-ticket-conversation', {
			table: data.table,
			sys_id: data.sys_id,
//      filter: filter_audit,
			includeExtended: true,
			title: "${Activity}",
			use_dynamic_placeholder: true,
			btnLabel: "${Post}"
		});

		// Activity formatter is hardcoded to set specific options
		for (var f in data.f._formatters) {
			var fm = data.f._formatters[f];
			if (fm.formatter == "activity.xml") {
				fm.hardcoded = true;
				fm.widgetInstance = $sp.getWidget('widget-ticket-conversation', {
					table: data.table,
					sys_id: data.sys_id,
//					filter: filter_audit,
					includeExtended: true,
					title: 'Audit/Notes', //"${Activity}",
					use_dynamic_placeholder: true,
					btnLabel: "${Post}"
				});
			} else if (fm.formatter == "com_glideapp_servicecatalog_veditor" || fm.formatter == "com_glideapp_questionset_default_question_editor") {
				var qsConfig = $sp.getValue('quick_start_config');
				if (qsConfig)
					qsConfig = JSON.parse(qsConfig)[0];
				fm.widgetInstance = $sp.getWidget(fm.widget, {
					table: data.table,
					sys_id: data.sys_id,
//					filter: filter_audit,
					readonly_variable_editor: qsConfig ? qsConfig.readonly_variable_editor : 'false'
				});
			} else
				fm.widgetInstance = $sp.getWidget(fm.widget, data);
		}
	}

	//------------------------------------------------------------------------------------------------------------------------
	// 4. DOC. INT INTEGRATION
	//------------------------------------------------------------------------------------------------------------------------
	//STRY0042042: DI Integration: Turn on/off DocInt Attachments and SNOW OOB Attachments
	//STRY0046049: DI Integration: Enable/Disable upload document feature to SharePoint
	// STRY0086644 - added check for DocId not provided	
	if (!data.hideDocuments && 
			data.DocIntON && (data.sys_id != -1 && data.sys_id != '') &&
		(data.table == 'x_153465_discovert_route_task_instance' ||
		 data.table == 'x_153465_discovert_discover_routing_template' ||
		 data.table == 'x_153465_discovert_route_tasks')) {

		// STRY0063505 | Added a check for both boolean and string value of true
		if (data.isActive == "true" || data.isActive == true) data.isActive = true;
		else data.isActive = false;
		// STRY0111049
		data._docint_widget = new x_dtll2_contentint.SFWHelper().getWidgetFormConfigurationTabs(data.table, data.view, data.sys_id);
		// STRY0122687 - count tabs
		if(data._docint_widget && data._docint_widget._docint_tabs){
			data.tabCount +=data._docint_widget._docint_tabs.length;
		}
	}

	//------------------------------------------------------------------------------------------------------------------------
	// END CUSTON
	//------------------------------------------------------------------------------------------------------------------------





	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

})($sp, input, data, options, gs);
